// src/pages/Dashboard.js
import React, { useState, useEffect } from "react";
import { useAuth } from "../context/AuthContext";
import api from "../api";
import ExpenseForm from "../components/ExpenseForm";
import ExpenseList from "../components/ExpenseList";
import SummaryCards from "../components/SummaryCards";

export default function Dashboard() {
  const { user, logout } = useAuth();
  const [expenses, setExpenses] = useState([]);
  const [total, setTotal] = useState(0);
  const [summary, setSummary] = useState({});
  const [showForm, setShowForm] = useState(false);
  const [editExpense, setEditExpense] = useState(null);
  const [filters, setFilters] = useState({ category: "", search: "" });
  const [loading, setLoading] = useState(true);

  const CATEGORIES = ["Food", "Travel", "Shopping", "Education", "Health", "Entertainment", "Other"];

  const fetchExpenses = async () => {
    try {
      const params = {};
      if (filters.category) params.category = filters.category;
      if (filters.search) params.search = filters.search;
      const [expRes, sumRes] = await Promise.all([
        api.get("/expenses", { params }),
        api.get("/expenses/summary"),
      ]);
      setExpenses(expRes.data.expenses);
      setTotal(expRes.data.total);
      setSummary(sumRes.data.summary);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchExpenses(); }, [filters]);

  const handleDelete = async (id) => {
    if (!window.confirm("Are you sure you want to delete this expense?")) return;
    try {
      await api.delete(`/expenses/${id}`);
      fetchExpenses();
    } catch (err) {
      alert("Could not delete expense.");
    }
  };

  const handleFormSuccess = () => {
    setShowForm(false);
    setEditExpense(null);
    fetchExpenses();
  };

  return (
    <div className="min-h-screen bg-gray-50">
      <nav className="bg-white border-b border-gray-200 px-4 py-3">
        <div className="max-w-5xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <span className="text-2xl">💰</span>
            <span className="font-bold text-gray-800">Expense Tracker</span>
          </div>
          <div className="flex items-center gap-4">
            <span className="text-sm text-gray-600">Hello, {user?.name}!</span>
            <button onClick={logout} className="text-sm text-red-500 hover:text-red-700 font-medium">Logout</button>
          </div>
        </div>
      </nav>
      <div className="max-w-5xl mx-auto p-4 space-y-6">
        <SummaryCards total={total} summary={summary} expenses={expenses} />
        <div className="bg-white rounded-xl border border-gray-200 p-4">
          <div className="flex flex-wrap gap-3 items-center justify-between">
            <div className="flex gap-3 flex-wrap">
              <input type="text" placeholder="Search expenses..." className="border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-400 w-48" value={filters.search} onChange={(e) => setFilters({ ...filters, search: e.target.value })} />
              <select className="border border-gray-300 rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-400" value={filters.category} onChange={(e) => setFilters({ ...filters, category: e.target.value })}>
                <option value="">All Categories</option>
                {CATEGORIES.map((c) => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
            <button onClick={() => { setEditExpense(null); setShowForm(true); }} className="bg-indigo-500 hover:bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-medium transition">
              + Add Expense
            </button>
          </div>
        </div>
        {(showForm || editExpense) && (
          <ExpenseForm expense={editExpense} categories={CATEGORIES} onSuccess={handleFormSuccess} onCancel={() => { setShowForm(false); setEditExpense(null); }} />
        )}
        {loading ? (
          <div className="text-center py-12 text-gray-400">Loading...</div>
        ) : (
          <ExpenseList expenses={expenses} onEdit={(e) => { setEditExpense(e); setShowForm(false); }} onDelete={handleDelete} />
        )}
      </div>
    </div>
  );
}
